import { watch, inject, InjectionKey } from 'vue';

interface RefreshStatus {
  value: boolean;
}

export const useRefresh = (callback: () => void) => {
  const refreshStatus = inject<RefreshStatus>('refreshStatus' as unknown as InjectionKey<RefreshStatus>);

  watch(
    () => refreshStatus?.value,
    (newVal: any, oldVal: any) => {
      if (newVal === true && newVal !== oldVal) {
        callback();
      }
    }
  );
};
