import ApiService from "@/api/api";

// 以promsie的形式获取 userInfo
export function getUserInfo(): any {
  return new Promise((resolve) => {
    window.ConnectWebViewBridgeSDK.getUserInfo((data: Record<string, any>) => {
      resolve(data);
    });
    // 兜底SDK没有回调的情况
    setTimeout(() => {
      resolve({ token: "", stu_talid: "" })
    }, 10000)
  });
}

export const getAllDuration = async () => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/data/parent/report/duration", {
    tal_id: stu_talid,
    token,
  });
};

export const getContentDuration = async (data: {date: string}) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/data/parent/report/stage-list-v2", {
    ...data,
    tal_id: stu_talid,
    token,
  });
};

export const getAppDuration = async (data: {search_date: string}) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/parent/api/v2/app-store/app-use-info", {
    ...data,
    child_tal_id: stu_talid,
    token,
  });
};
