// 获取金刚位角标信息
export const getDiamondPositionTips = async (params: { key: string[] }) => {
  const token = await getTokenByBridge();
  const promiseList = [];
  if (params.key.includes('applicationmanager')) {
    promiseList.push(getDiamondAppManagerTips());
  }

  const getPrimePositionTips = ApiService.post(
    '/parent/api/v1/home/prime-position-tips',
    {
      token,
      ...params
    }
  ).then(({ data: { data, errcode } }) => {
    if (errcode === 0) {
      const map = { ...data };
      const result: Record<string, any> = {};
      Object.keys(map).forEach((key) => {
        if (map[key]) {
          result[key] = Number(map[key].num);
        }
      });
      return result;
    } else {
      return {};
    }
  });

  promiseList.push(getPrimePositionTips);
  return Promise.all(promiseList);
};
// 获取应用待审核
export const getDiamondAppManagerTips = async () => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/app-store/wait-audit-pop/pull', {
    token
  }).then(({ data: { data, errcode } }) => {
    if (errcode === 0) {
      return {
        applicationmanager: Number(data.wait_audit_count)
      };
    } else {
      return {
        applicationmanager: 0
      };
    }
  });
};

